            <p>{{ t('Each module is powered by a dedicated multi-agent pipeline.','\u6bcf\u4e2a\u6a21\u5757\u7531\u4e13\u5c5e\u7684\u591a Agent \u6d41\u6c34\u7ebf\u9a71\u52a8\u3002') }}</p>
          </div>
